     1→/**
     2→ * MMS Maximo Polling Service
     3→ *
     4→ * Implements polling fallback mechanism for Maximo integration.
     5→ * When webhooks become unreliable (no delivery for configured timeout),
     6→ * this service automatically activates scheduled polling.
     7→ *
     8→ * Key responsibilities:
     9→ * - Monitor webhook health and detect stale connections
    10→ * - Schedule and manage BullMQ repeatable polling jobs
    11→ * - Deduplicate webhook vs polling updates
    12→ * - Track sync mode transitions (WEBHOOK → POLLING → HYBRID)
    13→ *
    14→ * Sync modes:
    15→ * - WEBHOOK: Primary mode, real-time updates via webhooks
    16→ * - POLLING: Fallback mode, scheduled pulls every 15 minutes
    17→ * - HYBRID: Both active during transition periods
    18→ *
    19→ * @see specs/007-integration.md Section 7.4.7
    20→ */
    21→
    22→import { eq, sql, isNull } from 'drizzle-orm';
    23→import { Queue } from 'bullmq';
    24→import { BaseService, MmsAttributes } from '../lib/services/base';
    25→import {
    26→  maximoWebhookHealth,
    27→  maximoIntegrationConfig,
    28→  maximoShadowRecords,
    29→  type MaximoWebhookHealth,
    30→} from '../lib/db/schema';
    31→import {
    32→  QUEUE_NAMES,
    33→  getQueue,
    34→  type MaximoSyncJobData,
    35→} from '../lib/queue';
    36→import {
    37→  maximoMetrics,
    38→  recordPollingFallbackActivation,
    39→  updateSyncModeMetric,
    40→} from '../lib/metrics';
    41→import { getMaximoSyncService, type PullResult } from './maximo-sync';
    42→
    43→// =============================================================================
    44→// Types
    45→// =============================================================================
    46→
    47→/** Sync mode type */
    48→export type SyncMode = 'WEBHOOK' | 'POLLING' | 'HYBRID';
    49→
    50→/** Polling configuration */
    51→export interface PollingConfig {
    52→  enabled: boolean;
    53→  intervalMinutes: number;
    54→  webhookTimeoutMinutes: number;
    55→  gracePeriodMinutes: number;
    56→  deduplicationWindowMs: number;
    57→}
    58→
    59→/** Default polling configuration */
    60→export const DEFAULT_POLLING_CONFIG: PollingConfig = {
    61→  enabled: true,
    62→  intervalMinutes: 15,
    63→  webhookTimeoutMinutes: 30,
    64→  gracePeriodMinutes: 5,
    65→  deduplicationWindowMs: 5000,
    66→};
    67→
    68→/** Webhook health status */
    69→export interface WebhookHealthStatus {
    70→  isHealthy: boolean;
    71→  lastReceivedAt: Date | null;
    72→  minutesSinceLastWebhook: number | null;
    73→  consecutiveFailures: number;
    74→  syncMode: SyncMode;
    75→  pollingActive: boolean;
    76→}
    77→
    78→/** Polling job result */
    79→export interface PollingResult {
    80→  processed: number;
    81→  updated: number;
    82→  conflicts: number;
    83→  errors: number;
    84→  duplicatesPrevented: number;
    85→  durationMs: number;
    86→  syncMode: SyncMode;
    87→}
