    89→// =============================================================================
    90→// Constants
    91→// =============================================================================
    92→
    93→/** BullMQ repeat job key prefix */
    94→const POLLING_JOB_KEY = 'maximo-polling';
    95→
    96→// =============================================================================
    97→// Singleton instance
    98→// =============================================================================
    99→
   100→let instance: MaximoPollingService | null = null;
   101→
   102→/**
   103→ * Get the singleton MaximoPollingService instance
   104→ */
   105→export function getMaximoPollingService(): MaximoPollingService {
   106→  if (!instance) {
   107→    instance = new MaximoPollingService();
   108→  }
   109→  return instance;
