/**
 * Maximo Webhook Health - tracks webhook delivery status for polling fallback
 *
 * When webhooks become unreliable (no delivery for configured timeout),
 * the system automatically activates polling fallback mode.
 *
 * Sync modes:
 * - WEBHOOK: Primary mode, webhooks deliver real-time updates
 * - POLLING: Fallback mode, scheduled pulls every N minutes
 * - HYBRID: Both active during transition periods
 *
 * @see specs/007-integration.md Section 7.4.7
 */
export const maximoWebhookHealth = pgTable(
  'maximo_webhook_health',
  {
