   488→          train: pm.train ? { id: pm.train.id, trainNumber: pm.train.trainNumber } : undefined,
   489→          pmType: pm.pmType
   490→            ? { id: pm.pmType.id, pmCode: pm.pmType.pmCode, pmName: pm.pmType.pmName }
   491→            : undefined,
   492→          depot: pm.assignedDepot
   493→            ? { id: pm.assignedDepot.id, code: pm.assignedDepot.code }
   494→            : undefined,
   495→        },
