  1039→        where: eq(maximoShadowRecords.syncStatus, 'SYNCED'),
  1040→        orderBy: [desc(maximoShadowRecords.lastSyncAt)],
  1041→      });
  1042→
  1043→      return {
  1044→        pendingRecords: statusCounts['PENDING'] ?? 0,
  1045→        syncedRecords: statusCounts['SYNCED'] ?? 0,
  1046→        conflictRecords: statusCounts['CONFLICT'] ?? 0,
  1047→        errorRecords: statusCounts['ERROR'] ?? 0,
  1048→        lastSyncAt: lastSync?.lastSyncAt ?? undefined,
