/**
 * MMS Maximo Sync Service Unit Tests
 *
 * Tests for the MaximoSyncService covering:
 * - Edit validation against Maximo status locks
 * - Shadow record management
 * - Sync status transitions
 * - Status mapping from Maximo to MMS
 * - Circuit breaker state handling
 *
 * Note: These tests use Bun's test framework.
 * Tests that require database are marked as integration tests.
 *
 * @see src/services/maximo-sync.ts
 * @see specs/007-integration.md Section 7.4
 */

import { describe, test, expect, beforeAll } from 'bun:test';
import {
  MaximoSyncService,
  getMaximoSyncService,
  MAXIMO_TO_MMS_STATUS,
  LOCKED_MAXIMO_STATUSES,
  MAXIMO_STATUS_LABELS,
  type MaximoWoStatus,
  type MmsPmStatus,
} from './maximo-sync';
import { sql } from '../lib/db/connection';

let databaseAvailable = false;

async function checkDatabaseConnection(): Promise<boolean> {
  try {
    await sql`SELECT 1`;
    return true;
  } catch {
    return false;
  }
}

describe('MaximoSyncService', () => {
  let service: MaximoSyncService;

  beforeAll(async () => {
    databaseAvailable = await checkDatabaseConnection();
    service = getMaximoSyncService();
  });

  describe('Singleton Pattern', () => {
    test('getMaximoSyncService returns singleton instance', () => {
      const service1 = getMaximoSyncService();
      const service2 = getMaximoSyncService();
      expect(service1).toBe(service2);
    });

    test('service is instance of MaximoSyncService', () => {
      expect(service).toBeInstanceOf(MaximoSyncService);
    });
  });

  describe('Status Mapping Constants', () => {
    test('MAXIMO_TO_MMS_STATUS maps all Maximo statuses', () => {
      const maximoStatuses: MaximoWoStatus[] = ['WAPPR', 'APPR', 'INPRG', 'COMP', 'CLOSE', 'CAN'];

      for (const status of maximoStatuses) {
        expect(MAXIMO_TO_MMS_STATUS[status]).toBeDefined();
        expect(typeof MAXIMO_TO_MMS_STATUS[status]).toBe('string');
      }
    });

    test('MAXIMO_TO_MMS_STATUS maps WAPPR and APPR to SCHEDULED', () => {
      expect(MAXIMO_TO_MMS_STATUS['WAPPR']).toBe('SCHEDULED');
      expect(MAXIMO_TO_MMS_STATUS['APPR']).toBe('SCHEDULED');
    });

    test('MAXIMO_TO_MMS_STATUS maps INPRG to IN_PROGRESS', () => {
      expect(MAXIMO_TO_MMS_STATUS['INPRG']).toBe('IN_PROGRESS');
    });

    test('MAXIMO_TO_MMS_STATUS maps COMP and CLOSE to COMPLETED', () => {
      expect(MAXIMO_TO_MMS_STATUS['COMP']).toBe('COMPLETED');
      expect(MAXIMO_TO_MMS_STATUS['CLOSE']).toBe('COMPLETED');
    });

    test('MAXIMO_TO_MMS_STATUS maps CAN to CANCELLED', () => {
      expect(MAXIMO_TO_MMS_STATUS['CAN']).toBe('CANCELLED');
    });

    test('LOCKED_MAXIMO_STATUSES contains correct statuses', () => {
      expect(LOCKED_MAXIMO_STATUSES).toContain('INPRG');
      expect(LOCKED_MAXIMO_STATUSES).toContain('COMP');
      expect(LOCKED_MAXIMO_STATUSES).toContain('CLOSE');
      expect(LOCKED_MAXIMO_STATUSES).toContain('CAN');
      expect(LOCKED_MAXIMO_STATUSES).not.toContain('WAPPR');
      expect(LOCKED_MAXIMO_STATUSES).not.toContain('APPR');
    });

    test('MAXIMO_STATUS_LABELS provides human-readable labels', () => {
      expect(MAXIMO_STATUS_LABELS['WAPPR']).toBe('Waiting Approval');
      expect(MAXIMO_STATUS_LABELS['APPR']).toBe('Approved');
